import React, { useState, useEffect, useRef } from 'react'
import blogService from './services/blogs'
import loginService from './services/login'
import Toggleable from './components/Toggleable'
import Loginform from './components/Loginform'
import Blogform from './components/Blogform'
import Renderblogs from './components/Renderblogs'
import Logout from './components/Logout'
import Notification from './components/Notification'
import BasicInfo from './components/BasicInfo'
import ShowFull from './components/ShowFull'
import ShowFullBlog from './components/ShowFullBlog'
import { useDispatch, useSelector } from 'react-redux'
import { setBlogs } from './reducers/blogsReducer'
import { setUser } from './reducers/userReducer'
import { setNotif } from './reducers/notifReducer'
import { getUsers } from './reducers/usersReducer'
import { BrowserRouter as Router, Switch, Route, Link } from 'react-router-dom'
import { Navbar, Container } from 'react-bootstrap'
import Register from './components/Register'


const style = {
  textDecoration: 'none',
  color: 'black',
  fontSize: '0.9rem'
}

const App = () => {
  const dispatch = useDispatch()

  useEffect(() => {
    dispatch(setNotif(null, 0))
  }, [])

  useEffect(() => {
    dispatch(setBlogs())
    dispatch(getUsers())
  }, [dispatch])

  const blogs = useSelector(state => state.blogs)
  const user = useSelector(state => state.user)
  const users = useSelector(state => state.users)
  const notif = useSelector(state => state.notif)
  const [username, setUsername] = useState('')
  const [password, setPassword] = useState('')

  const BlogFormRef = useRef()

  const handlePassChange = (event) => {
    setPassword(event.target.value)
  }

  const handleUserChange = (event) => {
    setUsername(event.target.value)
  }

  const handleLogin = async (event) => {
    event.preventDefault()
    setUsername('')
    setPassword('')
    try {
      const loggingUser = await loginService.login({ username, password })
      dispatch(setUser(loggingUser))
      blogService.setToken(loggingUser.token)
      window.localStorage.setItem(
        'loggedBlogappUser', JSON.stringify(loggingUser)
      )
    } catch (e) {
      dispatch(setNotif(e.response.data.error) , 3)
    }
  }

  const handleLogout = () => {
    window.localStorage.removeItem('loggedBlogappUser')
    dispatch(setUser(null))
  }

  useEffect(() => {
    const fetchedUser = window.localStorage.getItem('loggedBlogappUser')
    if(fetchedUser){
      const confirmedUser = JSON.parse(fetchedUser)
      dispatch(setUser(confirmedUser))
      blogService.setToken(confirmedUser.token)
    }
  }, [])

  return (
    <div>
      <Router>
        <Notification notif={notif}/>
        {user === null
          ?
          <div>
            <Loginform handlePassChange={handlePassChange} handleLogin={handleLogin} handleUserChange={handleUserChange}
              username={username} password={password}/>
            <Toggleable text={'register here'}>
              <Register/>
            </Toggleable>
          </div>
          :
          <div>
            <h3>
              <Container>
                <Navbar variant="light" bg="light">
                  <Container>
                    <Link style={style} to='/blogs'>Blogs</Link>
                    <Link style={style} to='/users'>Users</Link>
                    <Navbar.Brand><Logout handleLogout={handleLogout}/></Navbar.Brand>
                  </Container>
                </Navbar>
              </Container>
            </h3>
            <Switch>
              <Route path='/blogs/:id'>
                <ShowFullBlog/>
              </Route>
              <Route path='/users/:id'>
                <ShowFull user={user}/>
              </Route>
              <Route path='/users'>
                <BasicInfo users={users}/>
              </Route>
              <Route path='/blogs'>
                <Renderblogs blogs={blogs} user={user}/>
                <Toggleable text={'Add a new blog'} ref={BlogFormRef}>
                  <Blogform setNotif={() => dispatch(setNotif)} fetch={fetch} BlogFormRef={BlogFormRef}/>
                </Toggleable>
              </Route>
              <Route path='/'>
                <h2 style={{ textAlign: 'center', paddingTop: '5rem' }}>Huikee blogisovellus, klikkaa ylhäält Users tai Blogs</h2>
              </Route>
            </Switch>
          </div>
        }
      </Router>
    </div>
  )
}

export default App