import React from 'react'
import { Button, Form } from 'react-bootstrap'

const Loginform = ({ handlePassChange, handleLogin, handleUserChange, username, password }) => {
  return (
    <div key="loginForm">
      <br/>
      <h3>Login</h3>
      <Form onSubmit={handleLogin} key="loginform">
        <div key="usernameDiv">
          <Form.Label>username</Form.Label>
          <Form.Control id="username1"
            name="Username"
            value={username}
            type="text"
            onChange={handleUserChange}
          />
        </div>
        <div key="passwordDiv">
          <Form.Label>password</Form.Label>
          <Form.Control id="password1"
            name="Password"
            value={password}
            type="text"
            onChange={handlePassChange}
          />
        </div>
        <br/>
        <Button variant='dark' type="submit" id="loginButton">login</Button>
      </Form>
    </div>
  )
}

export default Loginform