import React, { useState } from 'react'
import { useParams } from 'react-router-dom'
import { useSelector, useDispatch } from 'react-redux'
import { setBlogs } from '../reducers/blogsReducer'
import blogService from '../services/blogs'
import axios from 'axios'
import { Button, FormControl } from 'react-bootstrap'

const style = {
  textDecoration: 'none'
}

const ShowFullBlog = () => {

  const [comment, setComment] = useState('')
  const handleChange = (e) => {
    setComment(e.target.value)
  }

  const postComment = async (id) => {
    if(comment.length < 1){
      setComment('')
      return null
    }
    const response = await axios.post(`/api/blogs/${id}/comments`, { comment })
    setComment('')
    return response
  }

  const dispatch = useDispatch()
  const iD = useParams().id
  const blogs = useSelector(state => state.blogs)
  const blog = blogs.find(blo => blo.id === iD)
  if(blog === undefined){
    return null
  }
  return(
    <div>
      <h2 className="titleClass">
        {blog.title}
      </h2>
      <div>
        Author: {blog.author}
      </div>
      <div>
        Url: <a style={style} target='_blank' href={`${blog.url}`} rel="noreferrer">{blog.url}</a>
      </div>
      <div>
        Likes: {blog.likes}
        <br/>
        <Button variant='primary' size='sm' className='likeButton' onClick={ async () => {
          await blogService.updateLikes(blog.id)
          dispatch(setBlogs())
        }
        }>like</Button>
        <div>
          <br/>
          <h3>comments: </h3>
          {blog.comments.map(com => <div key={com}> -{com} </div>)}
        </div>
        <div>
          <br/>
          <p>comment: </p>
          <FormControl value={comment} onChange={handleChange} />
          <br/>
          <Button variant='success' onClick={ async () => {
            await postComment(blog.id)
            dispatch(setBlogs())
          }}>post</Button>
        </div>
      </div>
    </div>
  )
}

export default ShowFullBlog