import userService from '../services/users'

export const getUsers = () => {
  return async dispatch => {
    const users = await userService.getUsers()
    dispatch({
      type: 'GETUSERS',
      data: users.data
    })
  }
}

export const usersReducer = (state = [], action) => {
  switch(action.type){
  case 'GETUSERS':
    return action.data
  default:
    return state
  }
}