export const setUser = (user) => {
  return async dispatch => {
    dispatch({
      type: 'SETUSER',
      data: user
    })
  }
}

export const userReducer = (state = null, action) => {
  switch(action.type){
  case 'SETUSER':
    return action.data
  case 'NULL':
    return null
  default:
    return state
  }
}