import React, { useState } from 'react'
import Blog from './Blog'
import BlogFull from './BlogFull'
import { Button } from 'react-bootstrap'
import { Table } from 'react-bootstrap'

const BlogFullOrNo = ({ blog, user }) => {
  const fullornostyle = {
    marginBottom: '0.5em',
  }
  const [visible, setVisible] = useState(false)
  const hideWhenVisible = { display: visible ? 'none' : '' }
  const showWhenVisible = { display: visible ? '' : 'none' }
  const toggleVisibility = () => {
    setVisible(!visible)
  }

  return(
    <Table striped style={fullornostyle} className='fullorpartial'>
      <tbody>
        <tr>
          <td style={hideWhenVisible} className='partial'>
            <Blog blog={blog}/>
            <Button variant="outline-secondary" size='sm' onClick={toggleVisibility} className="showMore">show more</Button>
          </td>
          <td style={showWhenVisible} className='full'>
            <BlogFull blog={blog} user={user}/>
            <Button variant="outline-secondary" size='sm' onClick={toggleVisibility}>show less</Button>
          </td>
        </tr>
      </tbody>
    </Table>
  )
}

export default BlogFullOrNo