import React from 'react'
import { Link } from 'react-router-dom'
import { Table } from 'react-bootstrap'

const style = {
  textDecoration: 'none',
}

const BasicInfo = ({ users }) => {
  return(
    <Table striped bordered>
      <tbody>
        <tr>
          <th>User</th>
          <th>Blogs</th>
        </tr>
        {users.map(user =>
          <tr key={user.id}>
            <td>
              <Link style={style} to={`/users/${user.id}`}>{user.name}</Link>
            </td>
            <td>
              {user.blogs.length}
            </td>
          </tr>
        )}
      </tbody>
    </Table>
  )
}

export default BasicInfo