import React from 'react'
import blogService from '../services/blogs'
import { setBlogs } from '../reducers/blogsReducer'
import { useDispatch } from 'react-redux'
import { setNotif } from '../reducers/notifReducer'
import { Button } from 'react-bootstrap'

const blogstyle = {
  marginBottom: '1em',
  padding: '0.5em'
}

const likestyle = {
  marginLeft: '0.3em'
}

const style = {
  textDecoration: 'none'
}

const BlogFull = ({ blog, user }) => {
  const dispatch = useDispatch()
  if(blog === undefined || user === undefined){
    return null
  }
  const ownBlog = ((user.name === blog.user.name) && (user.username === blog.user.username))
  let showOrNo = { display: 'none' }
  if(ownBlog){
    showOrNo = { display: '' }
  }
  return (
    <td style={blogstyle} id={blog.id}>
      <div className="titleClass">
      Title: {blog.title}
      </div>
      <div>
      Author: {blog.author}
      </div>
      <div>
       Url: <a style={style} target='_blank' rel="noreferrer"  href={`${blog.url}`}>{blog.url}</a>
      </div>
      <div>
      Likes: {blog.likes}
        <Button variant='primary' size='sm' className='likeButton' style={likestyle} onClick={ async () => {
          await blogService.updateLikes(blog.id)
          dispatch(setBlogs())
        }
        }>like</Button>
      </div>
      <div>
        <Button variant='danger' size='sm' style={showOrNo} onClick={ async () => {
          if(window.confirm(`Do you really want to delete ${blog.title} by ${blog.author}?`)){
            await blogService.deleteBlog(blog.id)
            dispatch(setBlogs())
            dispatch(setNotif(`${blog.title} has been deleted`, 3))
          }
        }}>delete</Button>
      </div>
    </td>
  )
}
export default BlogFull
