let to

export const setNotif = (notif, time=3) => {
  return async dispatch => {
    dispatch({
      type: 'SETNOTIF',
      data: notif
    })
    clearTimeout(to)
    to = setTimeout(() => {
      dispatch({
        type: 'NOTIFNULL',
        data: null
      })
    }, time*1000)
  }
}

export const notifReducer = (state = [], action) => {
  switch(action.type){
  case 'SETNOTIF':
    return action.data
  case 'NOTIFNULL':
    return action.data
  default:
    return state
  }
}