import blogService from '../services/blogs'

export const setBlogs = () => {
  return async dispatch => {
    const blogs = await blogService.getAll()
    dispatch({
      type: 'SETBLOGS',
      data: blogs
    })
  }
}

export const blogsReducer = (state = [], action) => {
  switch(action.type){
  case 'SETBLOGS':
    return action.data
  default:
    return state
  }
}