import React, { useState } from 'react'
import { Button, Form } from 'react-bootstrap'
import axios from 'axios'
import { useDispatch } from 'react-redux'
import { setNotif } from '../reducers/notifReducer'

const Register = () => {

  const dispatch = useDispatch()

  const [username, setUsername] = useState('')
  const [password, setPassword] = useState('')
  const [name, setName] = useState('')

  const handlePassChange = (e) => {
    setPassword(e.target.value)
  }

  const handleNameChange = (e) => {
    setName(e.target.value)
  }

  const handleUserChange = (e) => {
    setUsername(e.target.value)
  }

  const handleRegister = async (e) => {
    e.preventDefault()

    if(username.length < 4 || password.length < 4 || name.length < 1){
      dispatch(setNotif('Enter valid name, username and password', 4))
      setPassword('')
      setUsername('')
      setName('')
      return null
    }

    const user = {
      name,
      username,
      password,
      blogs: []
    }
    const newUser = await axios.post('/api/users', user)
    console.log(newUser)
    if(newUser.status === 201){
      dispatch(setNotif(`${user.name} has been registered`, 3))
      setPassword('')
      setUsername('')
      setName('')
    }
  }

  return (
    <div>
      <br/>
      <h3>Register</h3>
      <Form onSubmit={handleRegister}>
        <div>
          <Form.Label>name</Form.Label>
          <Form.Control value={name} onChange={handleNameChange}/>
        </div>
        <div>
          <Form.Label>username</Form.Label>
          <Form.Control value={username} onChange={handleUserChange}/>
        </div>
        <div>
          <Form.Label>password</Form.Label>
          <Form.Control value={password} onChange={handlePassChange}/>
        </div>
        <br/>
        <Button variant='dark' type="submit" id="loginButton">register</Button>
      </Form>
    </div>
  )
}

export default Register